#!/usr/bin/env python3
import sys
import re

def validate_yaml_syntax(file_path):
    """Basic YAML syntax validation"""
    errors = []
    warnings = []

    with open(file_path, 'r') as f:
        lines = f.readlines()

    # Check indentation consistency
    indent_stack = [0]
    prev_indent = 0

    for line_num, line in enumerate(lines, 1):
        stripped = line.rstrip()

        # Skip empty lines and comments
        if not stripped or stripped.startswith('#'):
            continue

        # Calculate indentation
        indent = len(line) - len(line.lstrip())

        # Check for tabs (YAML requires spaces)
        if '\t' in line:
            errors.append(f"Line {line_num}: Contains tabs (YAML requires spaces)")

        # Check indentation is multiple of 2
        if indent > 0 and indent % 2 != 0:
            warnings.append(f"Line {line_num}: Odd indentation (should be multiple of 2): {repr(stripped[:50])}")

        # Check for matching brackets/braces
        if '[' in line:
            if line.count('[') != line.count(']'):
                errors.append(f"Line {line_num}: Mismatched brackets: {repr(stripped[:50])}")
        if '{' in line:
            if line.count('{') != line.count('}'):
                errors.append(f"Line {line_num}: Mismatched braces: {repr(stripped[:50])}")

    return errors, warnings

if __name__ == '__main__':
    file_path = '/workspace/.github/workflows/ci.yml'
    errors, warnings = validate_yaml_syntax(file_path)

    print("=" * 60)
    print("YAML SYNTAX VALIDATION REPORT")
    print("=" * 60)
    print(f"\nFile: {file_path}\n")

    if errors:
        print(f"❌ ERRORS FOUND ({len(errors)}):")
        for error in errors:
            print(f"  • {error}")
    else:
        print("✓ No syntax errors found")

    if warnings:
        print(f"\n⚠ WARNINGS ({len(warnings)}):")
        for warning in warnings:
            print(f"  • {warning}")
    else:
        print("✓ No warnings")

    print("\n" + "=" * 60)

