#!/usr/bin/env python3
import re

def validate_github_workflow(file_path):
    """Validate GitHub Actions workflow YAML structure"""
    with open(file_path, 'r') as f:
        content = f.read()
        lines = content.split('\n')

    issues = []

    # Check required top-level keys
    if 'name:' not in content:
        issues.append("❌ Missing required 'name' field")
    if 'on:' not in content:
        issues.append("❌ Missing required 'on' field (trigger)")
    if 'jobs:' not in content:
        issues.append("❌ Missing required 'jobs' field")

    # Check indentation of main sections
    main_sections = ['name:', 'on:', 'jobs:']
    for section in main_sections:
        for i, line in enumerate(lines):
            if section in line:
                if line.startswith(' '):
                    issues.append(f"⚠ Line {i+1}: Top-level section '{section}' should not be indented")

    # Check for job structure
    if 'jobs:' in content:
        # Find all job definitions (should be indented under jobs)
        in_jobs = False
        job_count = 0
        for i, line in enumerate(lines):
            if 'jobs:' in line:
                in_jobs = True
                continue
            if in_jobs and line.strip() and not line.startswith(' '):
                in_jobs = False
            if in_jobs and re.match(r'^  \w+:', line):
                job_count += 1
                job_name = re.match(r'^  (\w+):', line).group(1)
                # Check if job has required fields
                if 'runs-on:' not in content:
                    issues.append(f"⚠ Job '{job_name}': Missing 'runs-on' field")
                if 'steps:' not in content:
                    issues.append(f"⚠ Job '{job_name}': Missing 'steps' field")

        if job_count == 0:
            issues.append("❌ No jobs found under 'jobs:' section")

    # Check for common syntax issues
    # Check for unclosed quotes
    for i, line in enumerate(lines):
        if line.strip() and not line.strip().startswith('#'):
            # Count quotes
            single_quotes = line.count("'") - line.count("\\'")
            double_quotes = line.count('"') - line.count('\\"')
            if single_quotes % 2 != 0:
                issues.append(f"⚠ Line {i+1}: Unclosed single quote")
            if double_quotes % 2 != 0:
                issues.append(f"⚠ Line {i+1}: Unclosed double quote")

    # Check uses: syntax
    uses_count = content.count('uses:')
    if uses_count > 0:
        for i, line in enumerate(lines):
            if 'uses:' in line:
                # Check format: uses: owner/repo@version
                if re.search(r'uses:\s*[\w\-]+/[\w\-]+@', line):
                    pass  # Good format
                elif re.search(r'uses:\s*docker://', line):
                    pass  # Docker format is OK
                else:
                    # Could be on next line or valid format
                    pass

    # Check runs-on syntax
    for i, line in enumerate(lines):
        if 'runs-on:' in line:
            runners = ['ubuntu-latest', 'ubuntu-22.04', 'ubuntu-20.04', 'macos-latest', 
                      'macos-13', 'windows-latest', 'windows-2022']
            valid = False
            for runner in runners:
                if runner in line:
                    valid = True
                    break
            if not valid and 'self-hosted' not in line:
                pass  # Could be a custom runner

    return issues

def main():
    file_path = '/workspace/.github/workflows/ci.yml'
    issues = validate_github_workflow(file_path)

    print("=" * 60)
    print("GITHUB ACTIONS WORKFLOW VALIDATION")
    print("=" * 60)
    print(f"\nFile: {file_path}\n")

    with open(file_path, 'r') as f:
        lines = f.readlines()

    print(f"Total lines: {len(lines)}")
    print(f"File size: {sum(len(line.encode()) for line in lines)} bytes")

    # Count structure
    job_count = sum(1 for line in lines if re.match(r'^  \w+:', line))
    step_count = sum(1 for line in lines if '- uses:' in line or '- run:' in line)

    print(f"Jobs found: {job_count}")
    print(f"Steps found: {step_count}")

    print("\n" + "-" * 60)
    print("VALIDATION RESULTS:\n")

    if issues:
        for issue in issues:
            print(f"  {issue}")
        print(f"\nTotal issues: {len(issues)}")
    else:
        print("  ✓ All validations passed!")
        print("  ✓ Proper YAML structure")
        print("  ✓ Valid GitHub Actions workflow")
        print("  ✓ Required fields present")
        print("  ✓ Indentation correct")

    print("\n" + "=" * 60)

if __name__ == '__main__':
    main()

